const item = $input.first().json;
const body = item.body && typeof item.body === 'object' ? item.body : item;

const text = (...values) => values.find((value) => typeof value === 'string' && value.trim())?.trim() || '';
const lower = (value) => text(value).toLowerCase();

const companyName = text(body.companyName, body.company, body.businessName, 'Unknown company');
const market = text(body.market, body.country, body.region, 'Morocco');
const problem = text(body.problem, body.challenge, body.request, body.message);
const channel = lower(body.channel, body.source, 'website');
const urgency = lower(body.urgency, body.timeline, 'standard');
const budget = lower(body.budget, body.budgetRange);
const language = text(body.language, body.preferredLanguage, 'fr');

const hasProblem = problem.length >= 20;
const hasBudget = Boolean(budget);
const isHighUrgency = ['urgent', 'this week', 'asap', 'now'].some((term) => urgency.includes(term));
const isWarmChannel = ['intch', 'referral', 'partner', 'whatsapp'].some((term) => channel.includes(term));
const isMoroccanMarket = ['morocco', 'maroc', 'ma', 'casablanca', 'rabat', 'marrakech', 'tanger', 'agadir'].some((term) => lower(market).includes(term));

const score = [hasProblem, hasBudget, isHighUrgency, isWarmChannel, isMoroccanMarket].filter(Boolean).length;
const qualification = score >= 4 ? 'hot' : score >= 2 ? 'warm' : 'early';

let recommendedOffer = 'Free AI Opportunity Audit';
if (qualification === 'hot') {
  recommendedOffer = 'Business Automation Sprint';
} else if (problem.match(/app|mvp|platform|dashboard|portal/i)) {
  recommendedOffer = 'MVP/App Launch Sprint';
} else if (problem.match(/whatsapp|support|customer|lead|sales/i)) {
  recommendedOffer = 'AI WhatsApp Assistant';
}

const nextAction = qualification === 'hot'
  ? 'Book a discovery call and prepare a paid pilot proposal.'
  : 'Offer a free 30-minute AI audit and collect workflow details.';

return [{
  json: {
    saeTemplate: 'first-ai-opportunity-intake',
    status: 'qualified',
    companyName,
    market,
    language,
    sourceChannel: channel,
    qualification,
    score,
    recommendedOffer,
    nextAction,
    summary: `${companyName} is a ${qualification} lead for ${recommendedOffer}.`,
    capturedAt: new Date().toISOString()
  }
}];
